#include <bits/stdc++.h>
using namespace std;
const int N=205;
int n,m,a[N],g[N][N];
void floyd(int k)
{
    for(int i=0;i<n;i++)
    {
        for(int j=0;j<n;j++)
        {
            if(g[i][j]>g[i][k]+g[j][k]) g[i][j]=g[i][k]+g[j][k];
        }
    }
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n>>m;
    memset(g,0x3f,sizeof(g));
    for(int i=1;i<=n;i++)
    {
        cin>>a[i-1];
        g[i-1][i-1]=0;
    }
    for(int i=1;i<=m;i++)
    {
        int x,y,z;
        cin>>x>>y>>z;
        g[x][y]=g[y][x]=z;
    }
    int q,num=0;
    cin>>q;
    while(q--)
    {
        int x,y,z;
        cin>>x>>y>>z;
        for(;num<n;num++)
        {
            if(a[num]>z) break;
            floyd(num);
        }
        if(a[x]>z||a[y]>z)
        {
            cout<<"-1\n";
            continue;
        }
        if(g[x][y]==0x3f3f3f3f) cout<<"-1\n";
        else cout<<g[x][y]<<'\n';
    }
    return 0;
}
